public class ErrorDetailHelper {

    public static String getFullStackTrace(Throwable throwable) {
        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        throwable.printStackTrace(pw);
        return sw.toString();
    }

    public static String[] getStackTraceEntries(Throwable throwable) {
        return Arrays.stream(throwable.getStackTrace())
                .map(StackTraceElement::toString)
                .toArray(String[]::new);
    }

    public static StatusRuntimeException buildDetailedError(
            int code,
            String message,
            Throwable exception,
            Map<String, String> internalState) {

        // Build DebugInfo with full stack trace
        DebugInfo.Builder debugInfoBuilder = DebugInfo.newBuilder()
                .setDetail("Exception: " + exception.getClass().getName() +
                        "\nMessage: " + exception.getMessage() +
                        "\nFull Stack Trace:\n" + getFullStackTrace(exception));

        for (String entry : getStackTraceEntries(exception)) {
            debugInfoBuilder.addStackEntries(entry);
        }

        // If there's a cause, include it
        if (exception.getCause() != null) {
            debugInfoBuilder.setDetail(debugInfoBuilder.getDetail() +
                    "\n\nCaused by: " + getFullStackTrace(exception.getCause()));
        }

        DebugInfo debugInfo = debugInfoBuilder.build();

        // Build ErrorInfo with internal state metadata
        Map<String, String> metadata = new HashMap<>();
        metadata.put("exception_class", exception.getClass().getName());
        metadata.put("exception_message", exception.getMessage() != null ? exception.getMessage() : "null");
        metadata.put("timestamp", java.time.Instant.now().toString());
        metadata.put("thread", Thread.currentThread().getName());

        if (internalState != null) {
            internalState.forEach((k, v) -> metadata.put("state_" + k, v));
        }

        ErrorInfo errorInfo = ErrorInfo.newBuilder()
                .setReason(exception.getClass().getSimpleName())
                .setDomain("com.example.debug")
                .putAllMetadata(metadata)
                .build();

        // Build the full Status with all details
        Status status = Status.newBuilder()
                .setCode(code)
                .setMessage(message + " | Root cause: " + exception.getMessage())
                .addDetails(Any.pack(debugInfo))
                .addDetails(Any.pack(errorInfo))
                .build();

        return StatusProto.toStatusRuntimeException(status);
    }

    public static StatusRuntimeException buildDatabaseError(
            Throwable exception,
            String sqlQuery,
            String connectionInfo,
            Map<String, String> dbState) {

        Map<String, String> internalState = new HashMap<>();
        internalState.put("sql_query", sqlQuery);
        internalState.put("connection_info", connectionInfo);
        internalState.put("db_error_code", extractDbErrorCode(exception));
        internalState.put("db_sql_state", extractSqlState(exception));

        if (dbState != null) {
            internalState.putAll(dbState);
        }

        return buildDetailedError(
                com.google.rpc.Code.INTERNAL_VALUE,
                "Database operation failed: " + exception.getMessage(),
                exception,
                internalState);
    }

    public static StatusRuntimeException buildValidationError(
            String fieldName,
            String fieldValue,
            String description,
            Throwable exception) {

        BadRequest.FieldViolation fieldViolation = BadRequest.FieldViolation.newBuilder()
                .setField(fieldName)
                .setDescription(description + " (value was: '" + fieldValue + "')")
                .build();

        BadRequest badRequest = BadRequest.newBuilder()
                .addFieldViolations(fieldViolation)
                .build();

        DebugInfo debugInfo = DebugInfo.newBuilder()
                .setDetail("Validation failed for field '" + fieldName + "': " + description +
                        (exception != null ? "\nException: " + getFullStackTrace(exception) : ""))
                .build();

        Map<String, String> metadata = new HashMap<>();
        metadata.put("field", fieldName);
        metadata.put("value", fieldValue);
        metadata.put("timestamp", java.time.Instant.now().toString());

        ErrorInfo errorInfo = ErrorInfo.newBuilder()
                .setReason("VALIDATION_ERROR")
                .setDomain("com.example.debug")
                .putAllMetadata(metadata)
                .build();

        Status status = Status.newBuilder()
                .setCode(com.google.rpc.Code.INVALID_ARGUMENT_VALUE)
                .setMessage("Validation error: " + description)
                .addDetails(Any.pack(badRequest))
                .addDetails(Any.pack(debugInfo))
                .addDetails(Any.pack(errorInfo))
                .build();

        return StatusProto.toStatusRuntimeException(status);
    }

    private static String extractDbErrorCode(Throwable exception) {
        if (exception instanceof java.sql.SQLException) {
            return String.valueOf(((java.sql.SQLException) exception).getErrorCode());
        }
        return "unknown";
    }

    private static String extractSqlState(Throwable exception) {
        if (exception instanceof java.sql.SQLException) {
            return ((java.sql.SQLException) exception).getSQLState();
        }
        return "unknown";
    }
}


